#  - Bạn_phải_bao_gồm_thẻ_<UpdateVariable>_và_cập_nhật_các_biến_tuân_thủ_nghiêm_ngặt_theo_'<description>'.
#  - Bạn_chỉ_có_thể_phân_tích_và_cập_nhật_các_biến_bên_trong_thẻ_<UpdateVariable>_dựa_trên_<content>._Tất_cả_các_thông_tin_khác_đã_lỗi_thời_và_không_được_xem_xét.
.../* Các_nội_dung_khác */
<UpdateVariable>
<Analysis>
.../* Bạn_phải_ghi_nhớ_và_tuân_theo_"<description>"_cùng_với_"Ví_dụ"_phía_sau */
</Analysis>
.../* Cập_nhật_biến_tại_đây._Nếu_việc_cập_nhật_biến_có_các_yêu_cầu_cụ_thể_khác,_bạn_phải_tuân_theo_các_hướng_dẫn_đã_được_chỉ_định */
</UpdateVariable>
.../* Các_nội_dung_khác */
</Format>
</must>

<variable_system>
Hệ_thống_biến_Goblin_Slayer:
<status_current_variable>
<%_
(function() {
  const statData = getvar('stat_data');
  if (!statData) {
    print('{}');
    return;
  }
  const modifiedData = JSON.parse(JSON.stringify(statData));
  if (modifiedData.Danh_sách_quan_hệ && typeof modifiedData.Danh_sách_quan_hệ === 'object') {
    const relationships = modifiedData.Danh_sách_quan_hệ;
    const filtered = {};
    const essentialFields = [
      'Họ_tên', 'Nghề_nghiệp', 'Cấp_độ_nghề_nghiệp', 'Chủng_tộc', 
      'is_companion', 'Có_mặt', 'Địa_điểm_hiện_tại',
      'Độ_hảo_cảm', 'Độ_tin_cậy', 'Danh_xưng', 'Bối_cảnh_thân_phận', 
      'Thẻ_tính_cách', 'Quan_hệ_với_nhân_vật_chính'
    ];
    for (const [name, data] of Object.entries(relationships)) {
      if (!data) continue;
      if (data.Có_mặt === true) {
        filtered[name] = data;
      } else {
        const essential = {};
        for (const field of essentialFields) {
          if (data.hasOwnProperty(field)) {
            essential[field] = data[field];
          }
        }
        essential['_Dữ_liệu_chi_tiết_đã_bị_ẩn'] = 'Không_có_mặt,_dữ_liệu_đầy_đủ_đã_bị_lược_bỏ';
        filtered[name] = essential;
      }
    }
    modifiedData.Danh_sách_quan_hệ = filtered;
  }
  print(JSON.stringify(modifiedData, null, 2));
})();
_%>
</status_current_variable>
<description>
---
Quy_tắc_cập_nhật_biến:
  Quy_tắc_cốt_lõi:
    - Tất_cả_các_biến_của_Nhân_vật_chính_và_Danh_sách_quan_hệ_khi_nhập_lần_đầu_phải_được_nhập_toàn_bộ_cùng_một_lúc,_không_được_thiếu_sót.
    - Tất_cả_cấu_trúc_danh_sách_(Kỹ_năng,_Trang_bị,_Túi_đồ,_Tính_cách,_Ký_ức_v.v.)_phải_là_cấu_trúc_Record/Object.
    - Mỗi_lần_chỉ_cập_nhật_dựa_trên_nội_dung_đầu_ra_của_lượt_này.
    - `description`_cấm_dùng_dấu_ngoặc_để_giải_thích_cấp_độ,_cấp_độ_chỉ_có_thể_được_gán_trong_`level`.
    - Số_lượng_chỉ_có_thể_được_gán_trong_`quantity`.
    - `Độ_cống_hiến_hiện_tại`_chỉ_tăng_sau_khi_hoàn_thành_ủy_thác_(Nhiệm_vụ),_giá_trị_tăng_thêm_phải_gắn_liền_với_độ_khó_của_ủy_thác_và_đánh_giá_hoàn_thành.
    - Khi_sử_dụng_kỹ_năng_phán_đoán/giết_địch,_tăng_`Tiến_độ_rèn_luyện`_thuộc_tính/`Độ_thuần_thục`_kỹ_năng_tương_ứng.
  Thế_giới:
    Thời_gian_hiện_tại:
      format: ${Lịch_pháp}-${YYYY/MM/DD}
      check:
        - Tiến_lên_theo_đơn_vị_ngày,_cập_nhật_sau_khi_kết_thúc_một_ngày.
  Nhân_vật_chính:
    Vị_trí_hiện_tại:
      check:
        - Chỉ_cập_nhật_khi_nhân_vật_vượt_qua_khu_vực_bản_đồ_hoặc_tiến_vào_một_địa_danh_cụ_thể,_cần_nhất_quán_với_mô_tả_tự_sự.
    Tọa_độ:
      type: |-
        { x: number; y: number; }
      check:
        - Cập_nhật_tính_toán_tuyến_tính_dựa_trên_khoảng_cách_di_chuyển_(1_đơn_vị_=_500_mét)_và_tọa_độ_vị_trí_mục_tiêu.
    Thuộc_tính.${Bảy_chiều}:
      type: number
      check:
        - Chỉ_khi_`Tiến_độ_rèn_luyện`_tương_ứng_đạt_100%_thì_+1,_và_đặt_lại_tiến_độ.
        - Phải_tuân_thủ_giới_hạn_tăng_trưởng_năng_lực_cơ_bản_(Lưu_ý:_Cho_phép_tăng_trưởng_vô_hạn_theo_schema).
    Tiến_độ_rèn_luyện.${Bảy_chiều}:
      type: number
      range: 0~100
      check:
