418.content:
Nhiệm vụ hệ thống_Cốt truyện chính Minh Triều:
  type: Bộ điều khiển logic
  description: Phụ trách việc tự động phân phát và luân chuyển nhiệm vụ cốt truyện chính Minh Triều
  code: |
    <%_
      // =================================================
      // Khu vực cấu hình
      // =================================================

      // Định nghĩa tên nhiệm vụ
      const TASK_1 = "Lần đầu vào Huanglong";
      const TASK_2 = "Lần đầu biết Cộng minh";
      const TASK_3 = "Anh Minh Sơ Tương Triệu";
      const TASK_4 = "Thành phố Kim Châu";

      // Từ khóa địa điểm (Bể khớp mờ)
      // Chỉ cần địa điểm hiện tại chứa bất kỳ từ nào dưới đây, thì coi như ở khu vực Huanglong
      const targetLocations = ["Huanglong", "Vân Lăng Cốc", "Kim Châu", "Trung Khúc Thai Địa", "Vô Quang Chi Sâm", "Hổ Khẩu Sơn Mạch"];

      // =================================================
      // Logic cốt lõi
      // =================================================

      let taskLog = getvar('Nhân vật chính.Nhật ký nhiệm vụ');
      let location = getvar('Nhân vật chính.Nơi ở') || "";

      // Khởi tạo cấu trúc dữ liệu
      if (!taskLog || typeof taskLog !== 'object') {
        taskLog = { "Đang tiến hành": {}, "Đã hoàn thành": {} };
      }
      if (!taskLog["Đang tiến hành"]) taskLog["Đang tiến hành"] = {};
      if (!taskLog["Đã hoàn thành"]) taskLog["Đã hoàn thành"] = {};

      let updated = false;

      // -------------------------------------------------
      // Giai đoạn 4: [Anh Minh Sơ Tương Triệu] -> [Thành phố Kim Châu]
      // Kích hoạt: Đang làm T3 VÀ cốt truyện đã tiến triển
      // -------------------------------------------------
      if (!updated && taskLog["Đang tiến hành"][TASK_3]) {
        // Điều kiện phán đoán ở đây có thể mở rộng tùy theo nhu cầu, ví dụ chỉ cần xác nhận đang ở Kim Châu là được
        delete taskLog["Đang tiến hành"][TASK_3];
        taskLog["Đã hoàn thành"][TASK_3] = {
          "Đánh giá hoàn thành": "Đường nét hoành tráng của thành phố Kim Châu đã ở ngay trước mắt, lời mời của Lệnh Doãn rốt cuộc có ý nghĩa gì, tất cả sẽ được hé lộ bên trong bức tường thành.",
          "Phần thưởng nhận được": "Tiến vào thành phố Kim Châu"
        };

        if (!taskLog["Đã hoàn thành"][TASK_4]) {
          taskLog["Đang tiến hành"][TASK_4] = {
            "Loại": "Cốt truyện chính/Điều tra",
            "Mục tiêu hiện tại": "Đến trước thành phố Kim Châu, rất nhiều thương nhân lữ khách đang xếp hàng trên cầu để vào thành (Trên cái cây ở phía sau, Tsubaki đã tìm thấy Hạt giống định mệnh của cô ấy). Vào trong thành, Bạch Chỉ (định đi đến Viện nghiên cứu báo cáo sự bất thường của Khu vực vô âm) và Ương Ương (đến Biên Đình xin chỉ thị trước, nhân tiện làm thủ tục gặp mặt cho {{user}}), thế là Xích Hà dẫn {{user}} đi tham quan giới thiệu thành phố Kim Châu, dạo chơi một vòng, rồi dẫn lên Biên Đình. Biên Đình có rất nhiều khách, Ương Ương nói đơn xin gặp mặt của rất nhiều người đã bị khuyên lui, tiếp đó truyền tin đến, {{user}} một mình đi vào gặp mặt, bạn đồng hành thì đợi ở bên ngoài. Đi vào phủ đệ, Lệnh Doãn không có ở đó (Tuế Chủ mất tích), cận vệ Tản Hoa mượn Thanh Ngân của mắt phải đối chiếu thân phận của {{user}} (Tần số rất giống Lệnh Doãn, đều rất thuần khiết), lộ ra nụ cười vui vẻ. Sau khi tự giới thiệu liền chuyển sang chuyện chính, Lệnh Doãn không có ở đó, Tản Hoa chuyển giao thay quà gặp mặt và tín vật (Kẹo (Tìm trẻ em tìm hiểu), Thiết bị ma đạo cỡ nhỏ (Tìm Viện nghiên cứu, nhân tiện nhờ Bạch Chỉ giúp tiến hành kiểm tra cơ thể và tìm hiểu thêm nội dung liên quan đến Minh Triều, suy đoán ý đồ tín vật của Lệnh Doãn), Lá cây, Quả màu đen), ba ngày sau Lệnh Doãn sẽ chính thức gặp mặt, Tản Hoa dường như không biết thêm thông tin nào nữa. Cô ấy giúp {{user}} nâng cấp Thiết bị Bàn Cổ, nâng cao cấp bậc quyền hạn, sắp xếp chỗ ở tại Biên Đình. Sau khi buổi gặp mặt kết thúc, tóm tắt ngắn gọn cuộc gặp mặt lần này cho Ương Ương và Xích Hà, quyết định bắt tay từ từng tín vật một, thu thập thông tin. Sau khi tiến hành điều tra kẹo và thiết bị ma đạo cỡ nhỏ, trời đã tối, gặp mặt Ương Ương và Xích Hà trước cửa Viện nghiên cứu, sau khi mỗi người chia sẻ trải nghiệm hôm nay thì về Biên Đình nghỉ ngơi (Sau khi đi, Flo và Thương Ngân của Tàn Tinh Hội xuất hiện tại địa điểm gặp mặt vừa rồi, mà trợ lực Tản Hoa do Lệnh Doãn sắp xếp thì giám thị động thái của bọn họ ở trên cao)",
            "Thuyết minh tiến độ": "Đây chính là thành phố Kim Châu, phồn vinh và náo nhiệt. Tín vật ẩn chứa thâm ý của Lệnh Doãn...",
            "Xem trước phần thưởng": "Nâng cấp quyền hạn Thiết bị Bàn Cổ"
          };
        }
        updated = true;
      }

      // -------------------------------------------------
      // Giai đoạn 3: [Lần đầu biết Cộng minh] -> [Anh Minh Sơ Tương Triệu]
      // Kích hoạt: Đang làm T2
      // -------------------------------------------------
      else if (!updated && taskLog["Đang tiến hành"][TASK_2]) {
        delete taskLog["Đang tiến hành"][TASK_2];
        taskLog["Đã hoàn thành"][TASK_2] = {
          "Đánh giá hoàn thành": "Đối mặt với kẻ địch mạnh Vô Quan Giả đột nhiên xuất hiện, bạn đã thể hiện ra lòng dũng cảm và thực lực phi phàm, hóa giải thành công nguy cơ.",
          "Phần thưởng nhận được": "Đánh bại Vô Quan Giả"
        };

        if (!taskLog["Đã hoàn thành"][TASK_3]) {
          taskLog["Đang tiến hành"][TASK_3] = {
            "Loại": "Cốt truyện chính/Cốt truyện",
            "Mục tiêu hiện tại": "Sau khi chiến thắng Vô Quan Giả, Vô Quan Giả hóa thành Tàn Hưởng, Xích Hà đối với Tàn Hưởng cấp bậc này cảm thán vận may thật tốt, Ương Ương nhìn thấy sự phiền muộn của {{user}}, bèn phổ cập khoa học về cơ chế và hệ thống đặc thù của khu vực Minh Triều. Tiếp đó Ương Ương đưa cho {{user}} Thiết bị Bàn Cổ hình hồ lô, nhưng cấp bậc Ổ Dữ Liệu của {{user}} là 0 không thể hấp thụ, Xích Hà an ủi ăn cơm phải ăn từng miếng một lát nữa đi bắt một con nhỏ trước, Bạch Chỉ cho rằng sự bất thường của Vân Lăng Cốc phải báo cáo với Biên Đình, nơi này không nên ở lâu. Đột nhiên {{user}} cảm thấy một trận sức mạnh thu hút, và bước lên trước mở bàn tay phải ra, dùng Thanh Ngân đột nhiên xuất hiện trên mu bàn tay hấp thụ Vô Quan Giả. Xích Hà đột nhiên từ phía sau lao ra, cảm thấy kinh ngạc đối với bản lĩnh của {{user}} (Nghi ngờ {{user}} có còn giữ lại năng lực nuốt chửng Tàn Tượng, nướng Tàn Hưởng hay không), Ương Ương quan tâm tình trạng cơ thể của {{user}} nhờ Bạch Chỉ sau khi đến thành phố Kim Châu thì kiểm tra trị liệu một chút, tiếp đó Ương Ương nói đến văn ngôn văn nhắc tới Thiên Nhân nạp Hài (Xác) vào cơ thể ở phần mở đầu trong 《Kỷ Thế Thông Giám》, Xích Hà đã giải thích một cách dễ hiểu. Đang định lên đường lần nữa, trước mắt xuất hiện hình chiếu ba chiều của Lệnh Doãn Kim Châu, cô ta lấy lý do Lễ Truy Nguyệt sắp đến gần, bày tỏ sự hoan nghênh đối với tất cả khách từ phương xa đến của Kim Châu, và an ủi tướng sĩ bày tỏ tinh thần Kim Châu, cuối cùng nói ra từ 'Quý khách', hẹn gặp ở Biên Đình. Ba người đều cảm thấy vị quý khách này chính là {{user}}, liền lên đường đi đến thành phố Kim Châu.",
            "Thuyết minh tiến độ": "Thể chất đặc biệt của bạn khiến những người bạn đồng hành bên cạnh cảm thấy kinh ngạc, mà vị Lệnh Doãn Kim Châu ở phương xa kia, dường như đã dự kiến được sự xuất hiện của bạn...",
            "Xem trước phần thưởng": "Đến thành phố Kim Châu"
          };
        }
        updated = true;
      }

      // -------------------------------------------------
      // Giai đoạn 2: [Lần đầu vào Huanglong] -> [Lần đầu biết Cộng minh]
      // Kích hoạt: Đang làm T1
      // -------------------------------------------------
      else if (!updated && taskLog["Đang tiến hành"][TASK_1]) {
        delete taskLog["Đang tiến hành"][TASK_1];
        taskLog["Đã hoàn thành"][TASK_1] = {
          "Đánh giá hoàn thành": "Bạn tỉnh lại ở một vùng đất xa lạ, mặc dù tràn ngập sự mê mang, nhưng may mắn quen biết hai người bạn đồng hành đáng tin cậy —— Ương Ương và Xích Hà.",
          "Phần thưởng nhận được": "Bạn bè: Ương Ương, Xích Hà"
        };

        if (!taskLog["Đã hoàn thành"][TASK_2]) {
          taskLog["Đang tiến hành"][TASK_2] = {
            "Loại": "Cốt truyện chính/Chiến đấu",
            "Mục tiêu hiện tại": "Sau khi bị Xích Hà làm cho tỉnh lại, Ương Ương vì trang phục của {{user}} không giống người Huanglong bản địa, bèn gọi {{user}} là Giao Bạc Giả, dưới sự dẫn dắt của Ương Ương và Xích Hà thoát khỏi Vân Lăng Cốc, trên đường đi khi nhìn thấy bức tượng của Giác ở Đài Ngọc Long thì nhìn thấy Giác trong đầu, sau khi trèo ra khỏi thung lũng đi đến phía trên Bình Điệp Thạch, đột nhiên trời đất tối sầm lại, nơi này trong khoảnh khắc biến thành Khu vực vô âm, mượn dù lượn hạ cánh xuống bãi bằng sau, Xích Hà phát hiện Bạch Chỉ đang ở một mình giữa Khu vực vô âm, Bạch Chỉ xác nhận lại tình trạng cơ thể của {{user}}. Đột nhiên, trước mắt {{user}} hiện lên hình ảnh tướng quân Kỵ Viêm dẫn quân đánh bại Vô Quan Giả. Đột nhiên, Bình Điệp Thạch đột nhiên biến thành Khu vực vô âm, chia tách {{user}} và hai người, {{user}} sẽ một mình đối mặt với Vô Quan Giả (Tầng cấp thực lực là Thanh ngọc), học cách vận dụng năng lực Cộng minh và chiến thắng nó (Hoặc đợi đến khi hai người đến cứu viện trước khi lượng máu của mình cạn kiệt)",
            "Thuyết minh tiến độ": "Sự dị biến của Vân Lăng Cốc xảy ra đột ngột, trận chiến chạm vào là nổ ngay!",
            "Xem trước phần thưởng": "Mở khóa năng lực Cộng minh"
          };
        }
        updated = true;
      }

      // -------------------------------------------------
      // Giai đoạn 1: Tự động nhận [Lần đầu vào Huanglong]
      // Kích hoạt: Chưa bắt đầu cốt truyện chính series này + Đang ở khu vực Huanglong
      // -------------------------------------------------
      else if (!updated) {
        // Phán đoán xem có phải là người mới của cốt truyện chính này hay không (tức là 4 nhiệm vụ này đều chưa từng làm cũng không đang làm)
        // Việc phán đoán ở đây là để phòng ngừa nhiệm vụ bị xáo trộn thứ tự, sẽ không ảnh hưởng đến các nhiệm vụ phụ tuyến khác trên người bạn
        const isNewcomer = !taskLog["Đang tiến hành"][TASK_1] && !taskLog["Đã hoàn thành"][TASK_1] &&
                           !taskLog["Đã hoàn thành"][TASK_2] &&
                           !taskLog["Đã hoàn thành"][TASK_3] &&
                           !taskLog["Đã hoàn thành"][TASK_4];

        // Khớp lỏng lẻo: Chỉ cần tên địa điểm chứa bất kỳ từ vựng nào trong targetLocations là được
        const inHuangLong = targetLocations.some(place => location.includes(place));

        if (isNewcomer && inHuangLong) {
          taskLog["Đang tiến hành"][TASK_1] = {
            "Loại": "Khám phá",
            "Mục tiêu hiện tại": "Khám phá vùng đất Huanglong này, và hôn mê sau một cuộc chạm trán đặc biệt, gặp gỡ hai cô gái (Ương Ương và Xích Hà)",
            "Thuyết minh tiến độ": "Vừa mới đặt chân lên vùng đất xa lạ này, núi đá cây cỏ xung quanh đều toát ra khí tức kỳ lạ. Phía trước dường như có một loại chấn động chưa biết nào đó...",
            "Xem trước phần thưởng": "Mở ra chuyến hành trình mới"
          };
          updated = true;
        }
      }

      // 5. Gửi thay đổi
      if (updated) {
        setvar('Nhân vật chính.Nhật ký nhiệm vụ', taskLog);
      }
    _%>
